              {
                "key": "QUANTITY_CHANGED",
                "name": "Quantity Changed"
              },
              {
                "key": "PRICE_CHANGED",
                "name": "Price Changed"
              },
              {
                "key": "CALCULATE",
                "name": "Calculate"
              },
              {
                "key": "CALCULATION_COMPLETE",
                "name": "Calculation Complete"
              }
            ],
            "transitions": [
              {
                "from": "idle",
                "to": "calculating",
                "event": "QUANTITY_CHANGED",
                "effects": [
                  [
                    "emit",
                    "RECALCULATE_TOTAL"
                  ]
                ]
              },
              {
                "from": "idle",
                "to": "calculating",
                "event": "PRICE_CHANGED",
                "effects": [
                  [
                    "emit",
                    "RECALCULATE_TOTAL"
                  ]
                ]
              },
              {
                "from": "calculating",
                "to": "calculated",
                "event": "CALCULATE",
                "effects": [
                  [
                    "compute",
                    "totalPrice",
                    "multiply",
                    [
                      "unitPrice",
                      "quantity"
                    ]
                  ],
                  [
                    "persist",
                    "update",
                    "CartItem",
                    "@entity"
                  ]
                ]
              },
              {
                "from": "calculated",
                "to": "idle",
                "event": "CALCULATION_COMPLETE",
                "effects": [
                  [
                    "emit",
                    "CART_TOTAL_UPDATED"
                  ]
                ]
              }
            ]
          }
