{
  "name": "Product Inventory",
  "version": "1.0.0",
  "orbitals": [
    {
      "name": "Product Inventory",
      "entity": {
        "name": "Product",
        "collection": "products",
        "fields": [
          {
            "name": "name",
            "type": "string",
            "required": true
          },
          {
            "name": "price",
            "type": "number",
            "required": true
          },
          {
            "name": "quantity",
            "type": "number",
            "required": true,
            "default": 0
          },
          {
            "name": "status",
            "type": "enum",
            "required": true,
            "default": "active",
            "enum": [
              "active",
              "inactive",
              "discontinued"
            ]
          },
          {
            "name": "description",
            "type": "string"
          },
          {
            "name": "sku",
            "type": "string"
          },
          {
            "name": "category",
            "type": "string"
          },
          {
            "name": "minStock",
            "type": "number",
            "default": 10
          }
        ]
      },
      "traits": [
        {
          "name": "ProductStatus",
          "category": "interaction",
          "linkedEntity": "Product",
          "stateMachine": {
            "states": [
              {
                "name": "Active",
                "isInitial": true
              },
              {
                "name": "LowStock"
              },
              {
                "name": "OutOfStock"
              },
              {
                "name": "Inactive"
              },
              {
                "name": "Discontinued"
              }
            ],
            "events": [
              {
                "key": "CHECK_STOCK",
                "name": "Check Stock"
              },
              {
                "key": "RESTOCK",
                "name": "Restock"
              },
              {
                "key": "DEACTIVATE",
                "name": "Deactivate"
              },
              {
                "key": "ACTIVATE",
                "name": "Activate"
              },
              {
                "key": "DISCONTINUE",
                "name": "Discontinue"
              },
              {
                "key": "STOCK_DEPLETED",
                "name": "Stock Depleted"
              }
            ],
            "transitions": [
              {
                "from": "Active",
                "to": "LowStock",
                "event": "CHECK_STOCK",
                "condition": "quantity <= minStock && quantity > 0",
                "effects": [
                  [
                    "emit",
                    "PRODUCT_LOW_STOCK",
                    {
                      "productId": "@entity.id",
                      "quantity": "@entity.quantity"
                    }
                  ]
                ]
              },
              {
                "from": "Active",
                "to": "OutOfStock",
                "event": "STOCK_DEPLETED",
                "condition": "quantity <= 0",
                "effects": [
                  [
                    "emit",
                    "PRODUCT_OUT_OF_STOCK",
                    {
                      "productId": "@entity.id"
                    }
                  ],
                  [
                    "update-field",
                    "status",
                    "inactive"
                  ]
                ]
              },
              {
                "from": "LowStock",
                "to": "Active",
                "event": "RESTOCK",
                "condition": "quantity > minStock",
                "effects": [
                  [
                    "emit",
                    "PRODUCT_RESTOCKED",
                    {
                      "productId": "@entity.id",
                      "quantity": "@entity.quantity"
                    }
                  ]
                ]
              },
              {
                "from": "LowStock",
                "to": "OutOfStock",
                "event": "STOCK_DEPLETED",
                "condition": "quantity <= 0",
                "effects": [
                  [
                    "emit",
                    "PRODUCT_OUT_OF_STOCK",
                    {
                      "productId": "@entity.id"
                    }
                  ],
                  [
                    "update-field",
                    "status",
                    "inactive"
                  ]
                ]
              },
              {
                "from": "OutOfStock",
                "to": "Active",
                "event": "RESTOCK",
                "condition": "quantity > minStock",
                "effects": [
                  [
                    "update-field",
                    "status",
                    "active"
                  ],
                  [
                    "emit",
                    "PRODUCT_RESTOCKED",
                    {
                      "productId": "@entity.id",
                      "quantity": "@entity.quantity"
                    }
                  ]
                ]
              },
              {
                "from": "OutOfStock",
                "to": "LowStock",
                "event": "RESTOCK",
                "condition": "quantity > 0 && quantity <= minStock",
                "effects": [
                  [
                    "update-field",
                    "status",
                    "active"
                  ]
                ]
              },
              {
                "from": "Active",
                "to": "Inactive",
                "event": "DEACTIVATE",
                "effects": [
                  [
                    "update-field",
                    "status",
                    "inactive"
                  ],
                  [
                    "emit",
                    "PRODUCT_DEACTIVATED",
                    {
                      "productId": "@entity.id"
                    }
                  ]
                ]
              },
              {
                "from": "Inactive",
                "to": "Active",
                "event": "ACTIVATE",
                "effects": [
                  [
                    "update-field",
                    "status",
                    "active"
                  ],
                  [
                    "emit",
                    "PRODUCT_ACTIVATED",
                    {
                      "productId": "@entity.id"
                    }
                  ]
                ]
              },
              {
                "from": "Active",
                "to": "Discontinued",
                "event": "DISCONTINUE",
                "effects": [
                  [
                    "update-field",
                    "status",
                    "discontinued"
                  ],
                  [
                    "emit",
                    "PRODUCT_DISCONTINUED",
                    {
                      "productId": "@entity.id"
                    }
                  ]
                ]
              },
              {
                "from": "Inactive",
                "to": "Discontinued",
                "event": "DISCONTINUE",
                "effects": [
                  [
                    "update-field",
                    "status",
                    "discontinued"
                  ],
                  [
                    "emit",
                    "PRODUCT_DISCONTINUED",
                    {
                      "productId": "@entity.id"
                    }
                  ]
                ]
              }
            ]
          }
        },
